// ─── Helpers ──────────────────────────────────────────────────

const CATEGORIES = [
  { key: 'all', label: 'All' },
  { key: 'authentication', label: 'Authentication' },
  { key: 'buying-guide', label: 'Buying Guide' },
  { key: 'brand-spotlight', label: 'Brand Spotlight' },
  { key: 'care', label: 'Care' },
  { key: 'market-trends', label: 'Market Trends' },
];

export function getAllTips() {
  return expertTips;
}

export function getFeaturedTips() {
  return expertTips.filter((t) => t.featured);
}

export function getTipById(id) {
  return expertTips.find((t) => t.id === id) || null;
}

export function getTipsByCategory(category) {
  if (!category || category === 'all') return expertTips;
  return expertTips.filter((t) => t.category === category);
}

export function getRelatedTips(tip, count = 3) {
  return expertTips
    .filter((t) => t.id !== tip.id && (t.category === tip.category || t.brand === tip.brand))
    .slice(0, count);
}

export function searchTips(query) {
  const q = query.toLowerCase().trim();
  if (!q) return expertTips;
  return expertTips.filter((t) =>
    t.title.toLowerCase().includes(q) ||
    t.subtitle.toLowerCase().includes(q) ||
    t.tags.some((tag) => tag.includes(q)) ||
    (t.brand && t.brand.toLowerCase().includes(q))
  );
}

export { CATEGORIES };
export default expertTips;
